		if (!reviewInProgress) {
			return;
		}

		if (isToolCallEventType("bash", event) && !isSafeReadOnlyBash(event.input.command)) {
			return {
				block: true,
				reason:
					"Read-only review mode is active. Only non-mutating inspection commands are allowed during /pr-review and /pr-rereview.",
			};
		}
	});

