function shellSplit(command: string): string[] {
	return command
		.split(/&&|\|\||;|\|/)
		.map((part) => part.trim())
		.filter(Boolean);
}

function isReadOnlyGitSegment(tokens: string[]): boolean {
	if (tokens.length < 2 || tokens[0] !== "git") {
		return false;
	}

	const subcommand = tokens[1];
	return new Set([
		"show",
		"diff",
		"diff-tree",
		"log",
		"rev-parse",
		"status",
		"ls-tree",
		"ls-files",
		"cat-file",
		"merge-base",
		"blame",
		"grep",
	]).has(subcommand);
}

function isReadOnlyUtilitySegment(tokens: string[]): boolean {
	if (tokens.length === 0) {
		return true;
	}

	const command = tokens[0];
	return new Set([
		"pwd",
		"ls",
		"find",
		"grep",
		"rg",
		"head",
		"tail",
		"sed",
		"awk",
		"cut",
		"sort",
		"uniq",
		"wc",
		"printf",
		"echo",
		"true",
		"false",
		"test",
		"basename",
		"dirname",
		"realpath",
	]).has(command);
}

function isSafeReadOnlyBash(command: string): boolean {
	if (!command.trim()) {
		return true;
	}

	if (/>|>>|<</.test(command)) {
		return false;
	}

	const forbiddenPatterns = [
		/\brm\b/,
		/\bmv\b/,
		/\bcp\b/,
		/\btouch\b/,
		/\bmkdir\b/,
		/\brmdir\b/,
		/\bchmod\b/,
		/\bchown\b/,
		/\btee\b/,
		/\btruncate\b/,
		/\binstall\b/,
		/\bpatch\b/,
		/\bsed\s+-i\b/,
		/\bperl\s+-p?i\b/,
		/\bgit\s+(fetch|pull|push|commit|add|apply|am|checkout|switch|restore|reset|revert|rebase|merge|cherry-pick|stash|tag|clean)\b/,
	];

	if (forbiddenPatterns.some((pattern) => pattern.test(command))) {
		return false;
	}

	for (const segment of shellSplit(command)) {
		const cleaned = segment.replace(/^\([^)]*\)\s*/, "").trim();
		if (!cleaned) {
			continue;
		}

		const tokens = cleaned.match(/(?:"[^"]*"|'[^']*'|\S+)/g) ?? [];
		if (tokens.length === 0) {
			continue;
		}

		if (isReadOnlyGitSegment(tokens) || isReadOnlyUtilitySegment(tokens)) {
			continue;
		}

		return false;
	}

	return true;
}

